<script setup lang="ts">
import {computed,onMounted,ref,watch} from 'vue';import {useRoute,useRouter} from 'vue-router';import WorkflowSteps from '../../components/agent/WorkflowSteps.vue';import AgentResultMap from '../../components/agent/AgentResultMap.vue';import {agentRequest} from '../../services/agentApi';
const route=useRoute(),router=useRouter();const taskId=String(route.params.taskId);const packageId=ref(String(route.params.packageId));const task=ref<any>();const bundle=ref<any>();const overlays=ref<any>();const selectedLegId=ref('');const tab=ref<'424'|'result'|'overlay'>('424');const mapOpen=ref(false);const compareState=ref<{text:string;running:boolean;report?:any;error?:string}>({text:'',running:false});/* 对比暂时收起；接口与 runCompare424 都留着，改回 true 即恢复。 */const COMPARE_VISIBLE=false;const error=ref('');const showGeo=ref(false);
const pkg=computed(()=>bundle.value?.package);const result=computed(()=>bundle.value?.result);const pir=computed(()=>result.value?.pir);const selectedLeg=computed(()=>pir.value?.legs?.find((l:any)=>l.legId===selectedLegId.value));const geometryMissing=computed(()=>result.value?.geojson?.features?.filter((f:any)=>f.properties?.featureType==='LEG'&&!f.geometry).length||0);
onMounted(load);watch(()=>route.params.packageId,()=>{packageId.value=String(route.params.packageId);load()});async function load(){try{[task.value,bundle.value]=await Promise.all([agentRequest(`/tasks/${taskId}`),agentRequest(`/packages/${packageId.value}/result`)]);selectedLegId.value=pir.value?.legs?.[0]?.legId||'';if(result.value?.procedureId){try{overlays.value=await agentRequest(`/procedures/${result.value.procedureId}/overlays`)}catch{overlays.value=undefined}}}catch(e){error.value=msg(e)}}function openPackage(id:string){router.push(`/agent-tasks/${taskId}/results/${id}`)}async function retry(){await agentRequest(`/packages/${packageId.value}/retry`,{method:'POST'});router.push(`/agent-tasks/${taskId}/packages`)}function fix(id:string){return pir.value?.fixes?.find((f:any)=>f.fixId===id)?.identifier||id||'—'}function constraint(value:any){if(!value||value.type==='NONE')return'—';return value.rawText||[value.type,value.lowerFt,value.upperFt].filter(x=>x!==null&&x!==undefined).join(' ')}function download(name:string,text:string,type:string){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([text],{type}));a.download=name;a.click();URL.revokeObjectURL(a.href)}async function copy424(){await navigator.clipboard.writeText(result.value?.candidate424?.text||'')}function legsOfRoute(route:any){return (pir.value?.legs||[]).filter((l:any)=>l.routeId===route.routeId).sort((a:any,b:any)=>a.sequence-b.sequence)}
// 源上有、结果没有——第 5 点要的缺失提示，跟着识别结果一起看才有用。
const completenessFindings=computed(()=>(result.value?.validations||[]).filter((v:any)=>String(v.ruleCode||'').startsWith('SOURCE_COMPLETENESS_')));
const blockingValidations=computed(()=>(result.value?.validations||[]).filter((v:any)=>!String(v.ruleCode||'').startsWith('SOURCE_COMPLETENESS_')&&(v.severity==='BLOCKER'||v.severity==='ERROR')));
const resolvedFixCount=computed(()=>(pir.value?.fixes||[]).filter((f:any)=>f.latitude!=null&&f.longitude!=null).length);
async function runCompare424(){if(!result.value?.procedureId||!compareState.value.text.trim())return;compareState.value.running=true;compareState.value.error=undefined;try{compareState.value.report=await agentRequest(`/procedures/${result.value.procedureId}/compare-424`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({referenceText:compareState.value.text})})}catch(e){compareState.value.error=msg(e)}finally{compareState.value.running=false}}
function msg(e:unknown){return e instanceof Error?e.message:String(e)}
</script>
<template><main v-if="task&&bundle" class="page"><WorkflowSteps :current="3"/><header><div><button @click="router.push(`/agent-tasks/${taskId}/packages`)">← 返回程序包分组</button><h1>{{pkg.procedureName}}</h1><p>{{task.airportIcao}} {{task.airportName}} · {{pkg.procedureCategory}} · RWY {{pkg.runways.join(', ')||'—'}}</p></div><div><span :class="['status',pkg.status]">{{pkg.status}}</span><button @click="retry">重新识别</button><button @click="download(`${pkg.procedureName}.geojson`,JSON.stringify(result?.geojson,null,2),'application/geo+json')">导出 GeoJSON</button><button class="primary" @click="download(`${pkg.procedureName}.424.txt`,result?.candidate424?.text||'','text/plain')">导出 424</button></div></header><p v-if="error" class="error">{{error}}</p><section class="result-layout"><aside class="packages"><h3>全部程序包</h3><div v-for="category in ['SID','STAR','APPROACH']" :key="category"><b>{{category}}</b><button v-for="item in task.packages.filter((p:any)=>p.procedureCategory===category)" :key="item.packageId" :class="{active:item.packageId===pkg.packageId}" @click="openPackage(item.packageId)"><span>{{item.procedureName}}</span><em>{{item.status}}</em></button></div></aside><section class="details"><nav><button :class="{active:tab==='424'}" @click="tab='424'">ARINC 424</button><button :class="{active:tab==='result'}" @click="tab='result'">识别结果</button><button :class="{active:tab==='overlay'}" :disabled="!overlays?.overlays?.length" @click="tab='overlay'">原图叠加</button><span class="spacer"></span><button @click="showGeo=true">GeoJSON 源码</button><!-- 地图不再占据常驻列：正文留给 424 与对比，航迹按需弹窗 --><button class="map-open" @click="mapOpen=true">航迹图</button></nav>
<section v-if="tab==='424'" :class="['candidate',{'no-compare':!COMPARE_VISIBLE}]"><div class="acts"><button @click="copy424">复制</button><button @click="download(`${pkg.procedureName}.424.txt`,result?.candidate424?.text||'','text/plain')">下载</button></div><pre>{{result?.candidate424?.text||'尚未生成 424 Candidate'}}</pre>
<!-- 对比紧跟记录：参考数据是用来读上面那段的，拆成两个标签就看不到被比对的原文。 -->
<section v-if="COMPARE_VISIBLE" class="compare-pane"><h3>与 Jeppesen 424 对比</h3><p class="hint">粘贴同一程序的参考记录，逐字段比对上面的结果。</p><textarea v-model="compareState.text" rows="6" placeholder="粘贴参考 424 静态文本（132 列记录）"></textarea><button class="primary" :disabled="compareState.running||!compareState.text.trim()||!result?.candidate424?.text" @click="runCompare424">{{compareState.running?'对比中…':'运行对比'}}</button><p v-if="!result?.candidate424?.text" class="hint">本程序尚未生成 424，无法对比。</p><p v-if="compareState.error" class="error">{{compareState.error}}</p><div v-if="compareState.report" class="compare-report"><p><b>匹配率 {{compareState.report.matchRate==null?'—':Math.round(compareState.report.matchRate*100)+'%'}}</b> · {{compareState.report.matchedLegs}}/{{compareState.report.totalLegs}} 腿匹配 · {{compareState.report.partialLegs}} 部分 · {{compareState.report.mismatchedLegs}} 不匹配</p><div v-for="proc in compareState.report.procedureResults" :key="proc.procedureName+(proc.transitionName||'')"><b>{{proc.procedureName}} {{proc.transitionName||proc.runway}}</b><p v-for="lr in proc.legResults.filter((l:any)=>l.status!=='MATCH')" :key="lr.sequence" class="compare-diff">#{{lr.sequence}} {{lr.status}}：{{lr.fieldResults.filter((f:any)=>!f.matched).map((f:any)=>`${f.field}: AI=${f.aiValue??'—'} / 424=${f.jeppesenValue??'—'}`).join('；')||'腿段缺失'}}</p></div></div></section></section>
<section v-else-if="tab==='result'" class="recognized"><div class="summary"><p><span>Route</span>{{pir?.routes?.length||0}}</p><p><span>Leg</span>{{pir?.legs?.length||0}}</p><p><span>Fix 有坐标</span>{{resolvedFixCount}}/{{pir?.fixes?.length||0}}</p></div><div v-for="route in pir?.routes||[]" :key="route.routeId" class="route"><h4>{{route.identifier}}<em>{{route.routeType}}</em></h4><p v-if="route.climbGradient?.percent" class="climb">最低爬升梯度 {{route.climbGradient.percent}}%<template v-if="route.climbGradient.untilAltitudeFt">，直至通过 {{route.climbGradient.untilAltitudeFt}} FT</template></p><table><tr v-for="leg in legsOfRoute(route)" :key="leg.legId" :class="{active:leg.legId===selectedLegId}" @click="selectedLegId=leg.legId"><td class="seq">{{leg.sequence}}</td><td class="pt">{{leg.pathTerminator}}</td><td>{{fix(leg.fromFixId)}} → {{fix(leg.toFixId)}}</td><td class="num">{{leg.course??'—'}}°</td><td class="num">{{leg.distanceNm??'—'}} NM</td><td class="num">{{constraint(leg.altitudeConstraint)}}</td></tr></table></div><section v-if="completenessFindings.length" class="completeness"><h4>源页比对：结果中缺失的内容（{{completenessFindings.length}}）</h4><p class="hint">由 AI 读原始页面得出，供人复核——它与识别同源，不作为拒出依据。</p><p v-for="(v,i) in completenessFindings" :key="i" class="finding">{{v.message}}</p></section><p v-if="blockingValidations.length" class="blocking">另有 {{blockingValidations.length}} 项规则校验未通过：{{blockingValidations.map((v:any)=>v.ruleCode).join('、')}}</p><!-- 424 生成的元信息挪到这里：424 标签只放记录本身 --><section v-if="result?.candidate424" class="gen-meta"><h4>424 生成</h4><p><span :class="['status',result.candidate424.status]">{{result.candidate424.status}}</span></p><p v-if="!result.candidate424.missingFields?.length" class="hint">已通过固定宽度生成与回读检查。</p><p v-for="field in result.candidate424.missingFields||[]" :key="field" class="finding">缺字段：{{field}}</p></section></section>
<section v-else class="overlay-scroll"><img v-for="name in overlays?.overlays||[]" :key="name" :src="`/api/agent/procedures/${result.procedureId}/files/${name}`" :alt="name"></section></section></section>
<div v-if="showGeo" class="modal" @click.self="showGeo=false"><article><header><h2>GeoJSON 源码</h2><button @click="showGeo=false">关闭</button></header><pre>{{JSON.stringify(result?.geojson,null,2)}}</pre></article></div>
<div v-if="mapOpen" class="modal map-modal" @click.self="mapOpen=false"><article><header><h2>{{pkg.procedureName}} · 航迹图</h2><span v-if="geometryMissing" class="warn">{{geometryMissing}} 条 Leg 坐标不足</span><button @click="mapOpen=false">关闭</button></header><div class="map-body"><AgentResultMap :geojson="result?.geojson" :selected-leg-id="selectedLegId" @select-leg="selectedLegId=$event"/></div><div class="legend"><span><i class="exact"></i>精确/明确坐标</span><span><i class="derived"></i>推导几何</span><span><i class="display"></i>显示几何</span><span><i class="missing"></i>未生成几何</span></div></article></div></main></template>
<style scoped>.page{padding:24px;color:#102a43}.page>header{display:flex;justify-content:space-between;align-items:end;margin:24px 0}.page>header h1{margin:8px 0}.page>header p{color:#627d98}.page>header button{border:1px solid #c8d2df;background:#fff;padding:9px 12px;border-radius:7px;margin-left:6px}.page>header>div:first-child button{border:0;padding-left:0;color:#52606d}.primary{background:#1769e0!important;color:#fff!important}.status{display:inline-block;padding:6px 9px;border-radius:6px;background:#e7f5ed;color:#237a4b;font-size:12px}.status.FAILED,.status.REQUIRES_REVIEW,.status.\34 24_INCOMPLETE{background:#feeceb;color:#b42318}.result-layout{display:grid;grid-template-columns:230px minmax(0,1fr);height:calc(100vh - 210px);min-height:650px;background:#fff;border-radius:14px;overflow:hidden}.packages{background:#f5f8fb;padding:18px;overflow:auto}.packages h3{margin-top:0}.packages>div>b{display:block;font-size:11px;color:#829ab1;margin:20px 5px 6px}.packages button{display:block;width:100%;border:0;background:none;text-align:left;padding:10px;border-radius:7px}.packages button.active{background:#dfeafa}.packages span,.packages em{display:block}.packages em{font-size:10px;color:#627d98;font-style:normal;margin-top:4px}.overlay-scroll{overflow:auto;padding:10px}.overlay-scroll img{width:100%;border:1px solid #dbe4ee;border-radius:7px;margin-bottom:8px}.details>nav button{border:0;background:none;padding:8px 12px;color:#52606d}.details>nav button.active{color:#174ea6;font-weight:700;border-bottom:2px solid #1769e0}.details>nav .spacer{flex:1}.details>nav .map-open{border:1px solid #c8d2df;border-radius:6px;margin-left:6px}.compare-pane textarea{width:100%;box-sizing:border-box;margin:8px 0;font-family:monospace;font-size:10px;border:1px solid #ccd6e0;border-radius:7px;padding:8px}.compare-report{background:#f5f8fb;padding:10px;border-radius:7px;margin-top:8px;font-size:12px}.compare-diff{color:#b45309;margin:3px 0;font-size:11px}.hint{font-size:11px;color:#627d98}.recognized .route h4{margin:12px 0 4px;font-size:13px}.recognized .route h4 em{color:#627d98;font-size:11px;font-style:normal;margin-left:6px}.recognized .climb{margin:0 0 4px;font-size:11px;color:#b45309}.recognized table{width:100%;border-collapse:collapse;font-size:11px}.recognized td{padding:4px;border-bottom:1px solid #f1f5f9}.recognized tr.active{background:#eaf2fd}.recognized .seq,.recognized .pt{color:#627d98;white-space:nowrap}.recognized .num{text-align:right;white-space:nowrap}.recognized .completeness{margin-top:14px;border-top:1px solid #edf1f5;padding-top:10px}.recognized .finding{font-size:11px;margin:4px 0}.recognized .blocking{margin-top:12px;font-size:11px;color:#b42318}.map-modal article{width:min(1180px,94vw);height:min(860px,92vh);display:flex;flex-direction:column;position:relative}.map-modal .map-body{flex:1;min-height:0}.map-modal .map-body :deep(.map){height:100%}.map-modal header .warn{margin-left:auto;margin-right:10px;color:#b45309;font-size:12px}.legend{position:absolute;left:28px;bottom:28px;background:#fff;padding:9px;border-radius:7px;box-shadow:0 2px 12px #102a4322;display:flex;gap:10px;font-size:11px}.legend i{display:inline-block;width:20px;border-top:3px solid;margin-right:4px}.legend .exact{border-color:#1769e0}.legend .derived{border-color:#00a67d}.legend .display{border-color:#d97706;border-top-style:dashed}.legend .missing{border-color:#94a3b8}.details{border-left:1px solid #e4eaf0;overflow:auto;display:flex;flex-direction:column}.details>nav{position:sticky;top:0;display:flex;align-items:center;background:#fff;border-bottom:1px solid #e4eaf0;padding:7px;z-index:2}.details>section{padding:16px}.summary{display:flex;gap:10px}.summary p{flex:1;background:#f4f7fa;padding:9px;margin:0}.summary span{display:block;color:#829ab1;font-size:10px}.legs{margin-top:14px}.legs button{display:grid;grid-template-columns:70px 1fr auto;width:100%;border:0;border-bottom:1px solid #edf1f5;background:#fff;padding:10px;text-align:left}.legs button.active{background:#eaf2fd}.legs span,.legs em{font-style:normal;color:#52606d}.leg-detail{background:#f5f8fb;padding:12px;margin-top:12px}.leg-detail dl{display:grid;grid-template-columns:1fr 1.3fr;gap:8px}.leg-detail dt{color:#627d98}.leg-detail dd{margin:0}.candidate .acts{display:flex;gap:8px;margin-bottom:8px}.candidate.no-compare pre{max-height:calc(100vh - 300px)}.candidate .compare-pane{margin-top:16px;border-top:1px solid #edf1f5;padding-top:12px}.candidate .compare-pane h3{margin:0 0 4px;font-size:13px}.recognized .gen-meta{margin-top:14px;border-top:1px solid #edf1f5;padding-top:10px}.recognized .gen-meta h4{margin:0 0 6px;font-size:13px}.candidate .acts button,.compare{border:1px solid #c8d2df;background:#fff;padding:7px;border-radius:6px}.modal pre{white-space:pre-wrap;word-break:break-all;background:#10233e;color:#dcecff;padding:12px;max-height:430px;overflow:auto}/* 132 列定宽记录：换行毁列对齐，宁可横向滚动 */.candidate pre{white-space:pre;background:#10233e;color:#dcecff;padding:12px;max-height:calc(100vh - 400px);min-height:300px;overflow:auto;font-family:ui-monospace,"Cascadia Mono",Consolas,monospace;font-size:11px;line-height:1.5}.compare{width:100%;margin-top:15px}.modal{position:fixed;inset:0;background:#102a4366;display:grid;place-items:center;z-index:100}.modal article{background:#fff;width:min(900px,90vw);max-height:85vh;padding:18px;border-radius:12px}.modal header{display:flex;justify-content:space-between}.modal pre{max-height:68vh}.error{background:#fee2e2;color:#991b1b;padding:12px}@media(max-width:1100px){.result-layout{grid-template-columns:190px 1fr;height:auto}}</style>
